     1→/**
     2→ * AI Terminal Component
     3→ * Persistent AI assistant with multi-provider chat interface
     4→ *
     5→ * Features:
     6→ * - Multiple AI providers (OpenRouter, Groq, HuggingFace, Mistral, Gemini, OpenAI, Anthropic, xAI)
     7→ * - Provider/model selection
     8→ * - Automatic fallback on errors
     9→ * - Usage tracking
    10→ * - Encrypted API key storage
    11→ */
    12→
    13→import React, { useState, useRef, useEffect, useCallback } from 'react';
    14→import { useTerminalStore } from '../stores/useTerminalStore';
    15→import { aiTerminalService } from '../services/aiTerminal';
    16→import { createDefaultRouter } from '../services/ai/providerRouter';
    17→import { ProviderSettings } from './ProviderSettings';
    18→import { ModelSelector } from './ModelSelector';
    19→import { UsageTracker } from './UsageTracker';
    20→import { TerminalHelpModal } from './TerminalHelpModal';
    21→import { Terminal as PhantomTerminal, Preview as PhantomPreview } from './PhantomShell';
    22→import { usePhantomShellStore } from '../stores/usePhantomShellStore';
    23→import { runCommand, createShellContext, setRouter as setAICommandRouter } from '../services/phantomShell';
    24→import ReactMarkdown from 'react-markdown';
    25→import rehypeSanitize, { defaultSchema } from 'rehype-sanitize';
    26→
    27→type TerminalMode = 'chat' | 'shell';
    28→
    29→/**
    30→ * Custom sanitization schema for AI-generated content
    31→ * Extends default schema to allow safe code elements while blocking dangerous ones
    32→ *
    33→ * Security: This prevents XSS attacks from malicious AI responses
    34→ */
    35→const sanitizeSchema = {
    36→  ...defaultSchema,
    37→  tagNames: [
    38→    // Text formatting
    39→    'p', 'br', 'strong', 'em', 'b', 'i', 'u', 's', 'del', 'ins', 'mark',
    40→    // Headings
    41→    'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
    42→    // Lists
    43→    'ul', 'ol', 'li',
    44→    // Code
    45→    'pre', 'code',
    46→    // Quotes & dividers
    47→    'blockquote', 'hr',
    48→    // Links (href will be sanitized)
    49→    'a',
    50→    // Tables
    51→    'table', 'thead', 'tbody', 'tr', 'th', 'td',
    52→    // Other safe elements
    53→    'span', 'div',
    54→  ],
    55→  attributes: {
    56→    ...defaultSchema.attributes,
    57→    a: ['href', 'title', 'target', 'rel'],
    58→    code: ['className'], // For syntax highlighting classes
    59→    pre: ['className'],
    60→    span: ['className'],
    61→    div: ['className'],
    62→  },
    63→  // Force safe link attributes
    64→  protocols: {
    65→    href: ['http', 'https', 'mailto'],
    66→  },
    67→};
    68→
    69→export const AITerminal: React.FC = () => {
    70→  const {
    71→    isOpen,
    72→    apiKey, // Legacy Gemini key
    73→    // model is legacy and unused - destructured but not assigned to avoid TS error
    74→    activeProvider,
    75→    activeModel,
    76→    providers,
    77→    encryptionPassword,
    78→    isPasswordExpired,
    79→    fallbackEnabled,
    80→    messages,
    81→    isStreaming,
    82→    setOpen,
    83→    setActiveProvider,
    84→    addMessage,
    85→    clearMessages,
    86→    setStreaming,
    87→  } = useTerminalStore();
    88→
    89→  const [input, setInput] = useState('');
    90→  const [streamingContent, setStreamingContent] = useState('');
    91→  const [showProviderSettings, setShowProviderSettings] = useState(false);
    92→  const [showModelSelector, setShowModelSelector] = useState(false);
    93→  const [showUsageTracker, setShowUsageTracker] = useState(false);
    94→  const [showHelpModal, setShowHelpModal] = useState(false);
    95→  const [fallbackNotification, setFallbackNotification] = useState<string | null>(null);
    96→  const [terminalMode, setTerminalMode] = useState<TerminalMode>('chat');
    97→
    98→  // Phantom Shell state
    99→  const phantomStore = usePhantomShellStore();
   100→  const [shellInput, setShellInput] = useState('');
   101→
   102→  const messagesEndRef = useRef<HTMLDivElement>(null);
   103→  const inputRef = useRef<HTMLTextAreaElement>(null);
   104→  const fallbackTimeoutRef = useRef<NodeJS.Timeout | null>(null);
   105→
   106→  // Initialize provider router
   107→  const [router] = useState(() => createDefaultRouter((failedProvider, _failedModel, nextProvider, nextModel, reason) => {
   108→    // Fallback notification callback
   109→    setFallbackNotification(
   110→      `⚠️ ${failedProvider} failed: ${reason}. Switched to ${nextProvider} (${nextModel}).`
   111→    );
   112→    // Clear any existing timeout to prevent memory leaks
   113→    if (fallbackTimeoutRef.current) {
   114→      clearTimeout(fallbackTimeoutRef.current);
   115→    }
   116→    fallbackTimeoutRef.current = setTimeout(() => setFallbackNotification(null), 5000);
   117→  }));
   118→
   119→  // Share router with AI command service (Phantom Shell)
   120→  useEffect(() => {
   121→    setAICommandRouter(router);
   122→  }, [router]);
   123→
   124→  // Cleanup timeout on unmount
   125→  useEffect(() => {
   126→    return () => {
   127→      if (fallbackTimeoutRef.current) {
   128→        clearTimeout(fallbackTimeoutRef.current);
   129→      }
   130→    };
   131→  }, []);
   132→
   133→  // Auto-scroll to bottom when messages change
   134→  useEffect(() => {
   135→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   136→  }, [messages, streamingContent]);
   137→
   138→  // Focus input when terminal opens
   139→  useEffect(() => {
   140→    if (isOpen) {
   141→      inputRef.current?.focus();
   142→    }
   143→  }, [isOpen]);
   144→
   145→  // Initialize AI service with API key (legacy Gemini)
   146→  useEffect(() => {
   147→    if (apiKey) {
   148→      aiTerminalService.setApiKey(apiKey);
   149→    }
   150→  }, [apiKey]);
   151→
   152→  // Configure router with active provider and model
   153→  useEffect(() => {
   154→    router.updateConfig({
   155→      primaryProvider: activeProvider,
   156→      primaryModel: activeModel,
   157→      fallbackEnabled: fallbackEnabled,
   158→    });
   159→  }, [activeProvider, activeModel, fallbackEnabled, router]);
   160→
   161→  // Initialize provider API keys from encrypted storage
   162→  useEffect(() => {
   163→    const initializeApiKeys = async () => {
   164→      if (encryptionPassword && !isPasswordExpired()) {
   165→        const allProviders = router.getAllProviders();
   166→        for (const [providerId, provider] of Object.entries(allProviders)) {
   167→          const providerConfig = providers[providerId];
   168→          if (providerConfig && providerConfig.encryptedApiKey) {
   169→            try {
   170→              const decryptedKey = await useTerminalStore.getState().getProviderApiKey(providerId, encryptionPassword);
   171→              if (decryptedKey) {
   172→                provider.setApiKey(decryptedKey);
   173→              }
   174→            } catch (error) {
   175→              console.error(`Failed to decrypt ${providerId} API key:`, error);
   176→            }
   177→          }
   178→        }
   179→      }
   180→    };
   181→
   182→    initializeApiKeys();
   183→  }, [encryptionPassword, isPasswordExpired, providers, router]);
   184→
   185→  // Keyboard shortcuts
   186→  useEffect(() => {
   187→    const handleKeyDown = (e: KeyboardEvent) => {
   188→      // Cmd/Ctrl + Shift + A to toggle terminal
   189→      if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key.toLowerCase() === 'a') {
   190→        e.preventDefault();
   191→        setOpen(!isOpen);
   192→      }
   193→    };
   194→
   195→    document.addEventListener('keydown', handleKeyDown);
   196→    return () => document.removeEventListener('keydown', handleKeyDown);
   197→  }, [isOpen, setOpen]);
   198→
   199→  // Phantom Shell: Handle terminal data input
   200→  const handleTerminalData = useCallback((data: string) => {
   201→    // Handle special keys
   202→    if (data === '\r') {
   203→      // Enter key - execute command
   204→      if (shellInput.trim()) {
   205→        const terminal = phantomStore.terminalInstance;
   206→        const context = createShellContext(
   207→          terminal ? { clear: () => terminal.clear(), write: (d: string) => terminal.write(d) } : null,
   208→          {
   209→            activeProjectId: phantomStore.activeProjectId,
   210→            commandHistory: phantomStore.commandHistory,
   211→            projects: phantomStore.projects,
   212→            createProject: phantomStore.createProject,
   213→          }
   214→        );
   215→
   216→        // Add to history
   217→        phantomStore.addToHistory({ command: shellInput });
   218→
   219→        // Execute command
   220→        terminal?.write('\r\n');
   221→        runCommand(shellInput, context, (output) => {
   222→          terminal?.write(output);
   223→        }).then((exitCode) => {
   224→          // Show prompt after command completes
   225→          terminal?.write(`\r\n\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ `);
   226→          if (exitCode !== 0) {
   227→            // Exit code shown for non-zero
   228→          }
   229→        });
   230→
   231→        setShellInput('');
   232→      } else {
   233→        // Empty enter - just show new prompt
   234→        phantomStore.terminalInstance?.write('\r\n\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ');
   235→      }
   236→    } else if (data === '\x7f' || data === '\b') {
   237→      // Backspace
   238→      if (shellInput.length > 0) {
   239→        setShellInput(prev => prev.slice(0, -1));
   240→        phantomStore.terminalInstance?.write('\b \b');
   241→      }
   242→    } else if (data === '\x03') {
   243→      // Ctrl+C - cancel current input
   244→      phantomStore.terminalInstance?.write('^C\r\n\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ');
   245→      setShellInput('');
   246→    } else if (data === '\x1b[A') {
   247→      // Up arrow - history navigation
   248→      const prevCmd = phantomStore.navigateHistory('up');
   249→      if (prevCmd !== null) {
   250→        // Clear current line and show previous command
   251→        phantomStore.terminalInstance?.write('\r\x1b[K\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ' + prevCmd);
   252→        setShellInput(prevCmd);
   253→      }
   254→    } else if (data === '\x1b[B') {
   255→      // Down arrow - history navigation
   256→      const nextCmd = phantomStore.navigateHistory('down');
   257→      phantomStore.terminalInstance?.write('\r\x1b[K\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ' + (nextCmd || ''));
   258→      setShellInput(nextCmd || '');
   259→    } else if (data.length === 1 && data >= ' ') {
   260→      // Regular printable character
   261→      setShellInput(prev => prev + data);
   262→      phantomStore.terminalInstance?.write(data);
   263→    }
   264→  }, [shellInput, phantomStore]);
   265→
   266→  // Show prompt when terminal is ready
   267→  const handleTerminalReady = useCallback(() => {
   268→    setTimeout(() => {
   269→      phantomStore.terminalInstance?.write('\x1b[35mphantom\x1b[0m:\x1b[36m~\x1b[0m$ ');
   270→    }, 100);
   271→  }, [phantomStore.terminalInstance]);
   272→
   273→  // Initialize prompt when switching to shell mode
   274→  useEffect(() => {
   275→    if (terminalMode === 'shell' && phantomStore.isTerminalReady) {
   276→      handleTerminalReady();
   277→    }
   278→  }, [terminalMode, phantomStore.isTerminalReady, handleTerminalReady]);
   279→
   280→  const handleSubmit = async (e: React.FormEvent) => {
   281→    e.preventDefault();
   282→    if (!input.trim() || isStreaming) return;
   283→
   284→    const userMessage = input.trim();
   285→    setInput('');
   286→
   287→    // Check if any provider is configured
   288→    const configuredProviders = router.getConfiguredProviders();
   289→    if (configuredProviders.length === 0) {
   290→      addMessage({
   291→        role: 'system',
   292→        content: '⚠️ No AI providers configured. Click the ⚙️ Settings button to add API keys.',
   293→      });
   294→      return;
   295→    }
   296→
   297→    // Check if active provider is configured
   298→    const activeProviderObj = router.getProvider(activeProvider);
   299→    if (!activeProviderObj || !activeProviderObj.isConfigured()) {
   300→      addMessage({
   301→        role: 'system',
   302→        content: `⚠️ Provider "${activeProvider}" is not configured. Please add an API key in Settings.`,
   303→      });
   304→      return;
   305→    }
   306→
   307→    // Add user message
   308→    addMessage({
   309→      role: 'user',
   310→      content: userMessage,
   311→    });
   312→
   313→    // Start streaming
   314→    setStreaming(true);
   315→    setStreamingContent('');
   316→
   317→    try {
   318→      // Send message using router (with automatic fallback)
   319→      const response = await router.sendMessage({
   320→        prompt: userMessage,
   321→        conversationHistory: messages.map((msg) => ({
   322→          role: msg.role as 'user' | 'assistant' | 'system',
   323→          content: msg.content,
   324→        })),
   325→        stream: true,
   326→        onChunk: (chunk) => {
   327→          setStreamingContent((prev) => prev + chunk);
   328→        },
   329→      });
   330→
   331→      // Add complete assistant message with provider/model metadata
   332→      addMessage({
   333→        role: 'assistant',
   334→        content: response.content,
   335→        provider: response.provider || activeProvider,
   336→        model: response.model || activeModel,
   337→      });
   338→    } catch (error) {
   339→      const errorMessage = error instanceof Error ? error.message : 'Unknown error occurred';
   340→      addMessage({
   341→        role: 'system',
   342→        content: `❌ Error: ${errorMessage}`,
   343→      });
   344→    } finally{
   345→      setStreaming(false);
   346→      setStreamingContent('');
   347→    }
   348→  };
   349→
   350→  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
   351→    if (e.key === 'Enter' && !e.shiftKey) {
   352→      e.preventDefault();
   353→      handleSubmit(e);
   354→    }
   355→  };
   356→
   357→  if (!isOpen) return null;
   358→
   359→  return (
   360→    <div
   361→      className={`
   362→        fixed top-0 right-0 h-screen
   363→        transition-transform duration-200 ease-in-out
   364→        ${isOpen ? 'translate-x-0' : 'translate-x-full'}
   365→        w-[300px] lg:w-[375px]
   366→        bg-white dark:bg-black
   367→        border-l border-border-light dark:border-border-dark
   368→        shadow-2xl
   369→        z-40
   370→        flex flex-col
   371→      `}
   372→    >
   373→      {/* Header - Terminal Style */}
   374→      <div className="flex items-center justify-between px-4 py-3 bg-black dark:bg-black text-green-400 border-b border-border-light dark:border-border-dark flex-shrink-0">
   375→        <div className="flex items-center gap-2 font-mono text-sm">
   376→          {/* Mode Toggle Tabs */}
   377→          <div className="flex bg-neutral-900 rounded-button p-0.5 gap-0.5">
   378→            <button
   379→              onClick={() => setTerminalMode('chat')}
   380→              className={`px-2 py-1 text-xs rounded-button transition-all ${
   381→                terminalMode === 'chat'
   382→                  ? 'bg-green-400/20 text-green-400'
   383→                  : 'text-neutral-400 hover:text-green-400'
   384→              }`}
   385→              title="AI Chat Mode"
   386→            >
   387→              💬 Chat
   388→            </button>
   389→            <button
   390→              onClick={() => setTerminalMode('shell')}
   391→              className={`px-2 py-1 text-xs rounded-button transition-all ${
   392→                terminalMode === 'shell'
   393→                  ? 'bg-accent-magenta/20 text-accent-magenta'
   394→                  : 'text-neutral-400 hover:text-accent-magenta'
   395→              }`}
   396→              title="Phantom Shell Terminal"
   397→            >
   398→              ⌨️ Shell
   399→            </button>
   400→          </div>
   401→          {terminalMode === 'chat' && (
   402→            <span className="text-green-400 text-xs">
   403→              {router.getConfiguredProviders().length > 0
   404→                ? `${activeProvider}/${activeModel}`
   405→                : 'no-provider'}
   406→            </span>
   407→          )}
   408→          {terminalMode === 'shell' && (
   409→            <span className="text-accent-magenta text-xs">phantom-shell</span>
   410→          )}
   411→        </div>
   412→
   413→        <div className="flex items-center gap-1">
   414→          {/* Fallback indicator */}
   415→          {fallbackEnabled && router.getConfiguredProviders().length > 1 && (
   416→            <span className="text-xs bg-green-400/20 px-2 py-0.5 rounded-button font-mono" title="Automatic fallback enabled">
   417→              🔄
   418→            </span>
   419→          )}
   420→
   421→          {/* Usage Tracker */}
   422→          <button
   423→            onClick={() => setShowUsageTracker(!showUsageTracker)}
   424→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   425→            title="Usage Statistics"
   426→            aria-label="View usage statistics"
   427→          >
   428→            📊
   429→          </button>
   430→
   431→          {/* Model Selector */}
   432→          <button
   433→            onClick={() => setShowModelSelector(!showModelSelector)}
   434→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   435→            title="Select Model"
   436→            aria-label="Select AI model"
   437→          >
   438→            🔀
   439→          </button>
   440→
   441→          {/* Provider Settings */}
   442→          <button
   443→            onClick={() => setShowProviderSettings(true)}
   444→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   445→            title="Provider Settings"
   446→            aria-label="Open provider settings"
   447→          >
   448→            ⚙️
   449→          </button>
   450→
   451→          {/* Help */}
   452→          <button
   453→            onClick={() => setShowHelpModal(true)}
   454→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-sm"
   455→            title="Help & Documentation"
   456→            aria-label="Open help"
   457→          >
   458→            ❓
   459→          </button>
   460→
   461→          {/* Close */}
   462→          <button
   463→            onClick={() => setOpen(false)}
   464→            className="p-1 hover:bg-green-400/20 rounded-button transition-all duration-standard ease-smooth text-base"
   465→            title="Close Terminal"
   466→            aria-label="Close AI terminal"
   467→          >
   468→            ✕
   469→          </button>
   470→        </div>
   471→      </div>
   472→
   473→      {/* Content Area - Chat or Shell */}
   474→      <div className="flex flex-col flex-1 overflow-hidden">
   475→        {/* Phantom Shell Terminal Mode */}
   476→        {terminalMode === 'shell' && (
   477→          <div className="flex flex-col flex-1 overflow-hidden">
   478→            {/* Preview Toggle Bar */}
   479→            <div className="flex items-center justify-between px-2 py-1 bg-neutral-900 border-b border-neutral-800 flex-shrink-0">
   480→              <span className="text-xs text-neutral-500">
   481→                {phantomStore.isDevServerRunning ? '🟢 Server running' : '⚫ No server'}
   482→              </span>
   483→              <button
   484→                onClick={() => phantomStore.setShowPreview(!phantomStore.showPreview)}
   485→                className={`px-2 py-0.5 text-xs rounded transition-all ${
   486→                  phantomStore.showPreview
   487→                    ? 'bg-cyan-500/20 text-cyan-400'
   488→                    : 'text-neutral-500 hover:text-cyan-400'
   489→                }`}
   490→                title="Toggle Preview Pane"
   491→              >
   492→                {phantomStore.showPreview ? '👁 Hide' : '👁 Show'} Preview
   493→              </button>
   494→            </div>
   495→
   496→            {/* Split View: Terminal (top) + Preview (bottom) */}
