     2→ * Password Prompt Component
     3→ * Handles encryption password setup and unlock for AI provider API keys
     4→ *
     5→ * Features:
     6→ * - Setup mode: Create new password with confirmation
     7→ * - Unlock mode: Enter existing password
     8→ * - Password strength validation (min 12 chars, complexity)
     9→ * - Configurable expiry (daily/weekly/monthly)
    10→ * - Show/hide password toggle
    11→ * - Security tips and best practices
    12→ */
    13→
    14→import { useState } from 'react';
    15→import { Modal } from './Modal';
    16→import { validatePassword, hashPassword } from '../services/encryption';
    17→
    18→interface PasswordPromptProps {
    19→  isOpen: boolean;
    20→  onSubmit: (password: string, passwordHash: string, duration: 'daily' | 'weekly' | 'monthly') => void;
    21→  onCancel: () => void;
    22→  mode: 'setup' | 'unlock';
    23→  existingPasswordHash?: string;
    24→}
    25→
    26→export function PasswordPrompt({
    27→  isOpen,
    28→  onSubmit,
    29→  onCancel,
    30→  mode,
    31→  existingPasswordHash,
    32→}: PasswordPromptProps) {
    33→  const [password, setPassword] = useState('');
    34→  const [confirmPassword, setConfirmPassword] = useState('');
    35→  const [duration, setDuration] = useState<'daily' | 'weekly' | 'monthly'>('weekly');
    36→  const [showPassword, setShowPassword] = useState(false);
    37→  const [error, setError] = useState<string | null>(null);
